 21→import io.github.oshai.kotlinlogging.KotlinLogging
 22→import io.ktor.http.ContentType.Text.Plain
 23→import io.ktor.server.application.Application
 24→import io.ktor.server.http.content.staticResources
 25→import io.ktor.server.response.respondText
 26→import io.ktor.server.routing.RoutingContext
 27→import io.ktor.server.routing.get
 28→import io.ktor.server.routing.routing
 29→import java.io.ByteArrayOutputStream
 30→import java.lang.management.ManagementFactory
 31→
 32→object Routes {
 33→  private val logger = KotlinLogging.logger {}
 34→
 35→  fun Application.configureRoutes() {
 36→    routing {
 37→      // This will redirect to the www subdomain
 38→      get("/") { redirectTo { "$URL_PREFIX/${EDIT.path}" } }
 39→
 40→      get(EDIT.path) {
 41→        val params = readQueryParams()
 42→        logger.info { params }
 43→        displayEdit(params)
 44→      }
 45→
 46→      get(GITHUB.path) {
 47→        val params = readQueryParams()
 48→        logger.info { params }
 49→        if (call.request.queryParameters.contains(EDIT.path)) {
 50→          displayEdit(params)
 51→        } else {
 52→          redirectTo { githubRangeUrl(params, URL_PREFIX).first }
 53→        }
 54→      }
 55→
 56→      get(PROBLEM.path) {
 57→        val params = readQueryParams()
 58→        val msg = readMsg()
 59→        displayException(params, msg)
 60→      }
 61→
 62→      get(WHAT.path) { displayWhat() }
 63→
 64→      get(CACHE.path) { displayCache() }
 65→
 66→      get(VERSION.path) { displayVersion() }
 67→
 68→      get(PING.path) { call.respondText("pong", Plain) }
 69→
 70→      get(THREADDUMP.path) {
 71→        try {
 72→          ByteArrayOutputStream()
 73→            .apply {
 74→              use { ThreadDumpInfo.threadDump.dump(true, true, it) }
 75→            }.let { baos ->
 76→              String(baos.toByteArray(), Charsets.UTF_8)
 77→            }
 78→        } catch (e: NoClassDefFoundError) {
 79→          "Sorry, your runtime environment does not allow dump threads."
 80→        }.also {
 81→          call.respondText(it, Plain)
 82→        }
 83→      }
 84→
 85→      get("robots.txt") {
 86→        call.respondText(
 87→          """
 88→            User-agent: *
 89→            Disallow: /error/
 90→            Disallow: /error
 91→          """.trimIndent(),
 92→          Plain,
 93→        )
 94→      }
 95→
 96→      staticResources("/", "public")
 97→    }
 98→  }
 99→
100→  private fun RoutingContext.readMsg() = call.request.queryParameters[MSG] ?: "Missing message value"
101→
102→  private fun RoutingContext.readQueryParams() =
103→    buildMap {
104→      QueryParams.entries
105→        .map { it.arg }
106→        .forEach { arg -> put(arg, call.request.queryParameters[arg]) }
107→    }
108→
109→  private object ThreadDumpInfo {
110→    val threadDump by lazy { ThreadDump(ManagementFactory.getThreadMXBean()) }
111→  }
112→}
